import{_ as a,c as o,o as n,a3 as t}from"./chunks/framework.IjbGqw7S.js";const p=JSON.parse('{"title":"Anti-Features in MMRL","description":"","frontmatter":{},"headers":[],"relativePath":"guide/antifeatures.md","filePath":"en/guide/antifeatures.md"}'),r={name:"guide/antifeatures.md"};function i(s,e,d,l,c,u){return n(),o("div",{"data-pagefind-body":!0},e[0]||(e[0]=[t('<h1 id="anti-features-in-mmrl" tabindex="-1">Anti-Features in MMRL <a class="header-anchor" href="#anti-features-in-mmrl" aria-label="Permalink to &quot;Anti-Features in MMRL&quot;">ŌĆŗ</a></h1><p>MMRL supports anti-features similar to F-Droid, allowing modules to be marked with characteristics users may want to avoid.</p><p>These anti-features can only be set in <code>track.json</code>:</p><div class="language-json vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;antifeatures&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Ads&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="list-of-anti-features" tabindex="-1">List of Anti-Features <a class="header-anchor" href="#list-of-anti-features" aria-label="Permalink to &quot;List of Anti-Features&quot;">ŌĆŗ</a></h2><h3 id="ads" tabindex="-1"><code>Ads</code> <a class="header-anchor" href="#ads" aria-label="Permalink to &quot;`Ads`&quot;">ŌĆŗ</a></h3><p>Includes advertising.</p><h3 id="tracking" tabindex="-1"><code>Tracking</code> <a class="header-anchor" href="#tracking" aria-label="Permalink to &quot;`Tracking`&quot;">ŌĆŗ</a></h3><p>Tracks and/or reports your activity, even if it can be turned off.</p><h3 id="nonfreenet" tabindex="-1"><code>NonFreeNet</code> <a class="header-anchor" href="#nonfreenet" aria-label="Permalink to &quot;`NonFreeNet`&quot;">ŌĆŗ</a></h3><p>Promotes or depends entirely on a non-changeable or non-free network service.</p><h3 id="nonfreeadd" tabindex="-1"><code>NonFreeAdd</code> <a class="header-anchor" href="#nonfreeadd" aria-label="Permalink to &quot;`NonFreeAdd`&quot;">ŌĆŗ</a></h3><p>Promotes other non-libre modules or plugins.</p><h3 id="nonfreedep" tabindex="-1"><code>NonFreeDep</code> <a class="header-anchor" href="#nonfreedep" aria-label="Permalink to &quot;`NonFreeDep`&quot;">ŌĆŗ</a></h3><p>Requires a non-libre module to function (e.g., Google Maps, Market).</p><h3 id="nsfw" tabindex="-1"><code>NSFW</code> <a class="header-anchor" href="#nsfw" aria-label="Permalink to &quot;`NSFW`&quot;">ŌĆŗ</a></h3><p>Contains content the user may not want to be publicized or visible everywhere.</p><h3 id="upstreamnonfree" tabindex="-1"><code>UpstreamNonFree</code> <a class="header-anchor" href="#upstreamnonfree" aria-label="Permalink to &quot;`UpstreamNonFree`&quot;">ŌĆŗ</a></h3><p>Upstream source code is not libre, with non-free parts replaced or rewritten.</p><h3 id="nonfreeassets" tabindex="-1"><code>NonFreeAssets</code> <a class="header-anchor" href="#nonfreeassets" aria-label="Permalink to &quot;`NonFreeAssets`&quot;">ŌĆŗ</a></h3><p>Includes non-libre media (e.g., images, sound, music, 3D models, video).</p><h3 id="knownvuln" tabindex="-1"><code>KnownVuln</code> <a class="header-anchor" href="#knownvuln" aria-label="Permalink to &quot;`KnownVuln`&quot;">ŌĆŗ</a></h3><p>Contains a known security vulnerability.</p><h3 id="nosourcesince" tabindex="-1"><code>NoSourceSince</code> <a class="header-anchor" href="#nosourcesince" aria-label="Permalink to &quot;`NoSourceSince`&quot;">ŌĆŗ</a></h3><p>Source code is no longer available, preventing new releases.</p><h3 id="obfuscation" tabindex="-1"><code>Obfuscation</code> <a class="header-anchor" href="#obfuscation" aria-label="Permalink to &quot;`Obfuscation`&quot;">ŌĆŗ</a></h3><p>Includes obfuscated code.</p><h3 id="unaskedremoval" tabindex="-1"><code>UnaskedRemoval</code> <a class="header-anchor" href="#unaskedremoval" aria-label="Permalink to &quot;`UnaskedRemoval`&quot;">ŌĆŗ</a></h3><p>Removes apps, permissions, or modules without user approval (excluding modules that disable other modules).</p><h3 id="llm" tabindex="-1"><code>LLM</code> <a class="header-anchor" href="#llm" aria-label="Permalink to &quot;`LLM`&quot;">ŌĆŗ</a></h3><p>Partially or fully written by an LLM.</p>',31)]))}const f=a(r,[["render",i]]);export{p as __pageData,f as default};
